var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"…보고 싶구나, 니콜.","JPN":"……会いたい、ニコル。","ENG":"...I miss you, Nicole.","TWN":"……真想見你，妮可。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"이 몸을 혼자 두고… 언제 돌아오는 것이냐.","JPN":"吾輩を一人にして……いつ帰ってくるつもりだ。","ENG":"Leaving me all alone... When are you coming back?","TWN":"把我一個人丟下……你究竟什麼時候才回來？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"모모?!","JPN":"モモ！？","ENG":"Momo?!","TWN":"莫莫？！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"미안.","JPN":"ごめんなさい。","ENG":"I'm sorry.","TWN":"對不起。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"계속 곁에 있었어야 했는데…","JPN":"ずっとそばにいるべきだったのに……","ENG":"I should've stayed by your side the whole time...","TWN":"我應該一直陪在你身邊的……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"못 지켜줘서 미안해요.","JPN":"守ってあげられなくてごめんなさい。","ENG":"I'm sorry I couldn't protect you.","TWN":"沒能保護你，對不起。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE_2"},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"정말 벌써 퇴원해도 괜찮겠어요?","JPN":"本当にもう退院して大丈夫なんですか？","ENG":"Are you really all right to be discharged already?","TWN":"真的已經可以出院了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"말했잖아. 별것 아니니까 금방 나을 거라고.","JPN":"言ったでしょ。大した傷じゃないからすぐ治るって。","ENG":"I told you. It's nothing serious, I'll recover soon enough.","TWN":"我不是說了嗎？沒什麼大不了的，很快就會好。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"사흘 동안 금식이라 인삼주스를 못 먹는 게 뼈아프긴 하지만… 어쩔 수 없, 콜록-","JPN":"3日絶食だから高麗人参ジュースが飲めないのは辛いけど……仕方な、げほっ。","ENG":"Three days of fasting and no ginseng juice hurts, but... it can't be hel– *Cough*","TWN":"雖然得禁食三天，不能喝人蔘汁這點很痛苦……但也沒辦法，咳—"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…입에서 피가 나는데요?","JPN":"……口から血を吐きましたけど？","ENG":"...You're bleeding from the mouth.","TWN":"……你嘴角在流血耶？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"이건… 나쁜 피를 걸러내는 거야. 오히려 좋은 거지.","JPN":"これは……悪い血を出してるの。逆にいいこと。","ENG":"This is... just filtering out bad blood. It's actually a good thing.","TWN":"這是……排出壞血，反而是好事。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"아무튼, 오늘 만나자고 한 용건은 그런 게 아니야.","JPN":"とにかく、今日呼び出した用件はそのことじゃなくて。","ENG":"Anyway, that's not why I asked to meet today.","TWN":"總之，今天約你出來不是為了這個。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"아, 그랬죠.","JPN":"あ、そうでしたね。","ENG":"Ah, right.","TWN":"啊，對。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그럼… 모모가 있던 시설의 보안카메라 복원에 성공한 건가요?","JPN":"では……モモがいた施設の防犯カメラのデータを復元できたんですか？","ENG":"Then... did you manage to restore the security camera footage from the facility where Momo was?","TWN":"那麼……已經成功復原莫莫所在設施的監控畫面了嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"침식 오염도가 높아서, 완벽한 복원에는 실패 했어.","JPN":"侵食汚染度が高すぎて完璧にはいかなかった。","ENG":"The Corruption Level was too severe for a full restoration.","TWN":"因為侵蝕污染度太高，沒能完全復原。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"하지만 손상이 덜한 녹화 프레임 몇 개를 살리는 덴 성공했지.","JPN":"でも損傷が少なかったフレームの一部は復元できたよ。","ENG":"But we did manage to salvage a few frames with minimal damage.","TWN":"不過，還是成功搶救了幾個受損比較不嚴重的畫面。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"적어도… 그곳에 뭐가 다녀간 건지는 알겠더라.","JPN":"少なくとも……あそこに何が来ていたかはわかった。","ENG":"At the very least... we know what passed through there.","TWN":"至少……能確認有什麼東西曾經去過那裡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"다녀간… 무언가?","JPN":"何かが……来ていた？","ENG":"Something... passed through...?","TWN":"去過那裡的……什麼？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"이거야.","JPN":"これ。","ENG":"This.","TWN":"就是這個。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L29_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"모모가 있던 방에서 확인된 존재의 정체.","JPN":"モモがいた部屋で確認された存在の正体。","ENG":"The identity of the entity confirmed in the room where Momo was.","TWN":"在莫莫房間內確認到的存在。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"이건… 누구죠?","JPN":"これは……誰ですか？","ENG":"Who... is that?","TWN":"這是……誰？"},"stage":{"bg":"OMEN_INTRO_03","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"타기리온.","JPN":"タギリオン。","ENG":"Thagirion.","TWN":"塔基里翁。"},"stage":{"bg":"OMEN_INTRO_03","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그라운드 원을 비롯해… 관리국이 지키던 도시들을 하룻밤에 쑥대밭으로 만든…","JPN":"グラウンド・ワンをはじめとして……管理局が守っていた都市を一晩で滅茶苦茶にした……","ENG":"The Demon Lord who turned Ground One... and the cities the Administration protected into ruins overnight.","TWN":"讓包括G1在內，由管理局守護的多座城市，一夜之間化為焦土的……"},"stage":{"bg":"OMEN_INTRO_03","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"마왕이야.","JPN":"魔王。","ENG":"A Demon Lord.","TWN":"魔王。"},"stage":{"bg":"OMEN_INTRO_03","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"마왕 타기리온이 모모의 앞에 나타나 손길을 뻗었고…","JPN":"魔王タギリオンがモモの前に現れて手を伸ばし……","ENG":"Demon Lord Thagirion appeared before Momo and reached out to her...","TWN":"魔王塔基里翁出現在莫莫面前，向她伸出手……"},"stage":{"bg":"OMEN_INTRO_03","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…모모의 뿔이 사라지면서, 그대로 잠들었어.","JPN":"……角が消え、モモはそのまま眠った。","ENG":"...And as Momo's horns vanished, she fell into a deep sleep.","TWN":"……隨著莫莫的角消失，她就這樣陷入沉睡。"},"stage":{"bg":"OMEN_INTRO_03","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"순전히 내 추측이지만…","JPN":"これは個人的な推測だけど……","ENG":"This is purely my speculation, but...","TWN":"純屬我的推測……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"모모가 깨어나지 못하는 건, 마왕이 그 아이한테서 무언가를 가져갔기 때문일 거야.","JPN":"モモが目を覚まさないのは、魔王があの子から何かを奪っていったからだと思う。","ENG":"The reason Momo hasn't woken up is probably because the Demon Lord took something from her.","TWN":"莫莫無法醒來，恐怕是因為魔王從她身上取走了某樣東西。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"마왕이… 그 아이한테 대체 뭘 원한 거죠?","JPN":"魔王は……あの子に何を望んでいるのでしょうか？","ENG":"What could the Demon Lord... possibly want from that child?","TWN":"魔王……究竟想從那孩子身上得到什麼？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"아무런 힘도 없는… 그 아이에게서 대체 뭘…!","JPN":"何の力もない……あの子にいったい何を……！","ENG":"From a child with no power at all... what could she possibly want...?!","TWN":"她明明什麼力量都沒有……究竟是為了什麼……！"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"침입자들이 했던 얘기, 기억나?","JPN":"侵入者たちの話、覚えてる？","ENG":"Do you remember what the intruders said?","TWN":"你還記得入侵者們說過的話嗎？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"암군이니, 작은 왕이니, 우리가 못 알아먹을 얘기만 잔뜩 해댔지만…","JPN":"暗君だの小さき王だの、わけのわからないことばかり言ってたけど……","ENG":"They kept rambling about things like the Ignorant Monarch and the little queen, none of it making sense to us...","TWN":"暗軍、小王……雖然全是些我們聽不懂的詞彙……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"돌이켜보면, 그 추종자들과 호박대가리의 말엔 공통점이 있었어.","JPN":"今思えば、追従者たちとカボチャ頭の話には共通する点があった。","ENG":"But looking back, there was one thing their words had in common with that pumpkin head.","TWN":"但仔細想想，那些追隨者與南瓜頭的話，其實有共通點。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"공통점… 이요?","JPN":"共通する点……？","ENG":"Something in common...?","TWN":"共通點……？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_OMEN_INTRO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"…듣듣고 이르되되, 수확의 때가 도래하였으니.","JPN":"……我ラ聞キテイワク、収穫の時は到来した。","ENG":"...Hearken and heed, for the time of harvest has come.","TWN":"……願聞其之，收穫之時已到來。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"작은 왕을 찾아 이방의 악마가 암군을 기만치 못하게 하라.","JPN":"小さき王を見つけ出し、異邦の悪魔が暗君を欺くことを阻止せよ。","ENG":"Find the little queen, and see that the foreign devil deceives the Ignorant Monarch no longer.","TWN":"尋找小王，莫讓異邦的惡魔欺瞞暗軍。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"암군은 결국 작은 왕을 거두고, 그분께서는 언약궤에 신의 열매를 담을 것이니.","JPN":"最後には暗君は小さき王を捕らえ、あのお方は契約の箱に神の実を収めるであろう。","ENG":"The Ignorant Monarch will ultimately claim the little queen, and she shall place the Godfruit within the Ark.","TWN":"暗軍終將回收小王。而那一位，會將神之果實置於約櫃。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"아주 오래 전…","JPN":"遠い昔……","ENG":"A very long time ago...","TWN":"很久以前……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"타기리온이라 불리는 마왕은 자신의 심장이나 다름없던 파편을 한 악마에게 빼앗겼습니다.","JPN":"タギリオンと呼ばれる魔王は、自分の心臓も同然だった破片をとある悪魔に奪われました。","ENG":"The Devil Lord known as Thagirion lost a fragment that was no different from her own heart, stolen by a devil.","TWN":"被稱為塔基里翁的魔王，曾被某個魔鬼奪走了如同自己心臟一樣重要的碎片。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"그 악마는 자신이 가장 아끼는 존재를 죽음으로부터 구하기 위해 마왕의 파편을 사용했고, 그 파편은 지금도 한 소녀의 몸 속에 깃들어 있죠.","JPN":"その悪魔は己の最も大事な存在を死より救うために魔王の破片を使い、その破片は今も一人の少女の身体に宿っています。","ENG":"That devil used the fragment to save the one they cherished most from death, and that fragment still dwells within a young girl even now.","TWN":"那個魔鬼為了拯救自己最珍愛之人免於死亡，使用了魔王的碎片。而那個碎片，至今仍寄宿在某個少女體內。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"작은 왕은 악도, 선도 되지 못함이라.","JPN":"小さき王は悪にも善にもなれぬ。","ENG":"The little queen is neither evil nor good.","TWN":"小王，非善亦非惡。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"그 존재는 단지, 암군이 지닌 감정의 편린. 암군의 결점에 지나지 않으니.","JPN":"かの存在はただ暗君の感情の片鱗。暗君の欠点にすぎぬ。","ENG":"That being is merely a fragment of the Ignorant Monarch's emotions. Nothing more than her flaw.","TWN":"僅是暗軍情感的碎片，不過是缺陷的象徵。"},"stage":{"bg":"TERRA","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"마왕의… 결점?","JPN":"魔王の……欠点？","ENG":"The Demon Lord's... flaw?","TWN":"魔王的……缺陷？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"맞아, 결점.","JPN":"そう、欠点。","ENG":"That's right. A flaw.","TWN":"沒錯，缺陷。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그게 정확히 어떤 건진 몰라도, 모모가 그 결점이라면 앞뒤가 얼추 맞아떨어져.","JPN":"具体的にそれが何かはわからないけど、モモがその欠点だとしたら辻褄が合う。","ENG":"I don't know exactly what it is, but if Momo is that flaw, then everything lines up.","TWN":"雖然還不知道那究竟是什麼，但若莫莫正是那個缺陷，一切就說得通了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"타기리온은 자기 결점을 적의 곁에 두지 않기 위해서 그걸 가지러 나타난 거야.","JPN":"タギリオンは自分の欠点を敵の傍に置きたくないから、それを取りに来たんだ。","ENG":"Thagirion came to retrieve it so as not to leave her flaw at an enemy's side.","TWN":"塔基里翁為了不讓自己的弱點落在敵人手中，才會現身將其取回。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"모모를 깨어 있게 해주던 것이… 마왕 타기리온의 결점…","JPN":"モモを動かしていたものが……魔王タギリオンの欠点……","ENG":"What kept Momo awake... was the Demon Lord Thagirion's flaw...","TWN":"讓莫莫得以清醒的東西……正是魔王塔基里翁的缺陷……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그레모리 씨는… 대체 저에게 뭘 숨기고 계셨던 걸까요?","JPN":"グレモリーさんは……いったい私に何を隠していたんでしょうか？","ENG":"What on earth was Gremory... hiding from me?","TWN":"葛茉莉……究竟對我隱瞞了什麼呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"우리도 그 사람 행방 찾고는 있지만 오리무중이야.","JPN":"私たちもその人の行方を調べているけど、今のところ五里霧中。","ENG":"We've been trying to track her down too, but it's a dead end.","TWN":"我們也在追查他的行蹤，但毫無線索。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"떠난 흔적이 없거든. 마치 연기처럼 사라졌어.","JPN":"動いた痕跡が見当たらない。まるで煙みたいに消えてる。","ENG":"There's no trace of her. She vanished into thin air.","TWN":"沒有任何離去的痕跡，彷彿化作一縷煙霧消失了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…민하 씨.","JPN":"……ミウさん。","ENG":"...Minha.","TWN":"敏荷……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"嗯……？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"저에게 보여주신 사진, 마왕에 대한 정보… 이것들 전부 관리국 입장에선 대외비인 거죠?","JPN":"私に見せてくれた写真、魔王の情報……これらは全部、管理局からすると機密なんですよね。","ENG":"The photo you showed me, the information about the Demon Lord... All of this would be classified from the Administration's perspective, right?","TWN":"你給我看的照片、關於魔王的情報……這些對管理局而言，都是機密吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"저한테 이걸 보여준 이유. 들어봐도 될까요?","JPN":"それを私に教えてくれた理由を聞いていいですか？","ENG":"May I ask why you showed it to me?","TWN":"我可以聽聽把這些告訴我的理由嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"우리 둘 다 겪어봤잖아.","JPN":"お互い経験して知ってるじゃん。","ENG":"We've both experienced it.","TWN":"我們都經歷過，不是嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"이 세상 너머에 얼마나 터무니없이 강한 존재가 있는지.","JPN":"この世界の向こうに、とんでもなく強い存在がいるって。","ENG":"How absurdly powerful the beings beyond this world are.","TWN":"這個世界之外，存在著多麼荒謬強大的存在。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그런 존재가 내게 있어 가장 소중한 사람을 노린다는 걸 알았을 때… 나 자신이 얼마나 무력해지는지.","JPN":"そんな存在が自分にとって一番大切な人を狙ってるって知った時……自分がどれだけ無力になるのか。","ENG":"And when you realize such a being is targeting the person you treasure most... how helpless you become.","TWN":"當你知道那樣的存在，盯上自己最珍視的人時……會明白自己有多麼無力。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"내 인생을 휩쓸고 간 폭풍을, 고작 내 부채질 따위로 어찌 해볼 수 없단 걸 알면서도…","JPN":"自分の人生を滅茶苦茶にした嵐を私の扇子なんかでどうにかできるわけないってわかってるけど……","ENG":"Even knowing I can't do anything about the storm that swept through my life with nothing more than my fan...","TWN":"明知那席捲人生的暴風，不是靠一己之力轉向……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"지나간 폭풍을 잊은 채 다른 삶을 살 순 없다는 거, 난 알고 있거든.","JPN":"その嵐を忘れて新しい人生を生きることなんてできない。私にはわかる。","ENG":"I know you can't just forget a storm that's already passed and go on living another life.","TWN":"卻也無法假裝什麼都沒發生，繼續過著別的人生。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그 악마가 말했었죠.","JPN":"あの悪魔が言ってましたね。","ENG":"That devil said it before.","TWN":"那名魔鬼說過。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"당신의 증오는 당신이 미래에 마주하게 될 진정한 숙적을 위해 아껴두라고…","JPN":"あなたの憎悪は、将来向き合うことになる真の宿敵のためにとっておけと……","ENG":"To save my hatred for the true enemy I would face in the future...","TWN":"要你把憎恨，留給未來真正要面對的宿敵……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"악마는 그 사람의 운명을 들여다볼 수 있다고 해요.","JPN":"悪魔はその人の運命を覗き見ることができるといいます。","ENG":"They say devils can see a person's fate.","TWN":"聽說魔鬼能看見人的命運。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"타기리온을 만나는 건, 처음부터 제 운명이었다는 거죠.","JPN":"タギリオンに会うのは、最初から決められた運命だったということです。","ENG":"Meeting Thagirion was my fate from the very beginning.","TWN":"那麼，遇見塔基里翁，或許從一開始就是我的命運。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그 말이 진실이라 해도 이길 거란 말은 한 적 없잖아?","JPN":"それが本当だとしても、勝てるとは言ってないじゃん。","ENG":"Even if that's true, she never said you'd win, did she?","TWN":"就算那是真的，也沒有人說你一定能贏吧？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"결말을 알고 있을 필요는 없어요.","JPN":"結末を知る必要はありません。","ENG":"I don't need to know the ending.","TWN":"不需要知道結局。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"결국 부딪힐 운명이라면, 할 수 있는 최선을 다할 뿐.","JPN":"どうせぶつかることが決まってる運命なら、できる限りの最善を尽くすだけです。","ENG":"If it's a fate I'm bound to clash with, I'll just do everything I can.","TWN":"若終究是要撞見的命運，那就只要盡全力就好。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"민하 씨도 저만큼 잘 알잖아요?","JPN":"ミウさんも私と同じぐらい、わかってるじゃないですか。","ENG":"You know that just as well as I do, don't you?","TWN":"敏荷，你不是比我更清楚嗎？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그럼 결정된 거네.","JPN":"じゃあ決まりだね。","ENG":"Then it's decided.","TWN":"那就這麼決定了。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"따라와.","JPN":"ついてきて。","ENG":"Follow me.","TWN":"跟我來。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"네? 어디로 가는데요?","JPN":"え？　どこに行くんですか？","ENG":"Huh? Where are we going?","TWN":"咦？要去哪？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"시니어가 데려 오래.","JPN":"シニアが連れてこいって。","ENG":"The Senior wants to see you.","TWN":"Senior要見你。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"본인 의사만 확인되면, 작전에 껴도 된다더라.","JPN":"本人の意思さえ確認できれば、作戦に加えてもいいんだってさ。","ENG":"Said you can join the operation, as long as it's your own decision.","TWN":"只要確認你本人的意願，就可以加入作戰。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"작전?","JPN":"作戦？","ENG":"An operation?","TWN":"作戰？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};